using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ServerShipmentService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments.OrderByDescending(s => s.CreatedDate).ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        return await db.Shipments.FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
    }

    public async Task<List<Shipment>> GetShipmentsByCustomerAsync(string customerEmail)
    {
        return await db.Shipments
            .Where(s => s.CustomerEmail == customerEmail)
            .OrderByDescending(s => s.CreatedDate)
            .ToListAsync();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        shipment.TrackingNumber = GenerateTrackingNumber();
        shipment.CreatedDate = DateTime.UtcNow;
        shipment.Status = ShipmentStatus.Pending;
        db.Shipments.Add(shipment);
        await db.SaveChangesAsync();
        return shipment;
    }

    public async Task<Shipment> UpdateShipmentStatusAsync(int id, ShipmentStatus status)
    {
        var shipment = await db.Shipments.FindAsync(id)
            ?? throw new InvalidOperationException("Shipment not found");
        shipment.Status = status;
        if (status == ShipmentStatus.Delivered)
        {
            shipment.ActualDelivery = DateTime.UtcNow;
        }
        await db.SaveChangesAsync();
        return shipment;
    }

    private static string GenerateTrackingNumber()
    {
        return $"ST-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(100000, 999999)}";
    }
}

